import android.content.Context
import android.content.Intent
import androidx.activity.result.ActivityResultLauncher
import androidx.activity.result.contract.ActivityResultContracts
import androidx.appcompat.app.AppCompatActivity
import com.facebook.CallbackManager
import com.facebook.FacebookCallback
import com.facebook.FacebookException
import com.facebook.login.LoginManager
import com.facebook.login.LoginResult
import com.google.android.gms.auth.api.signin.GoogleSignIn
import com.google.android.gms.auth.api.signin.GoogleSignInAccount
import com.google.android.gms.auth.api.signin.GoogleSignInClient
import com.google.android.gms.auth.api.signin.GoogleSignInOptions
import com.google.android.gms.common.api.ApiException
import com.google.android.gms.tasks.Task

sealed class SocialLoginResult {
    data class Success(
        val provider: SocialProvider,
        val authorizationCode: String?, // Send this to your backend to exchange for tokens
        val userId: String?,
        val email: String?,
        val displayName: String?
    ) : SocialLoginResult()

    data class Error(
        val provider: SocialProvider,
        val message: String,
        val exception: Exception? = null
    ) : SocialLoginResult()

    data class Cancelled(val provider: SocialProvider) : SocialLoginResult()
}

enum class SocialProvider {
    FACEBOOK,
    GOOGLE
}

interface SocialLoginCallback {
    fun onResult(result: SocialLoginResult)
}

class SocialLoginManager(
    private val activity: AppCompatActivity,
    private val callback: SocialLoginCallback
) {
    // Facebook
    private val facebookCallbackManager: CallbackManager = CallbackManager.Factory.create()
    private val facebookLoginManager: LoginManager = LoginManager.getInstance()

    // Google
    private val googleSignInClient: GoogleSignInClient
    private lateinit var googleSignInLauncher: ActivityResultLauncher<Intent>

    init {
        setupFacebookLogin()
        googleSignInClient = setupGoogleLogin()
        registerGoogleLauncher()
    }

    private fun setupFacebookLogin() {
        facebookLoginManager.registerCallback(
            facebookCallbackManager,
            object : FacebookCallback<LoginResult> {
                override fun onSuccess(result: LoginResult) {
                    // Send the access token to your BACKEND SERVER
                    // Your backend validates it with Facebook using the app secret
                    callback.onResult(
                        SocialLoginResult.Success(
                            provider = SocialProvider.FACEBOOK,
                            authorizationCode = result.accessToken.token,
                            userId = result.accessToken.userId,
                            email = null, // Fetch via Graph API on backend
                            displayName = null
                        )
                    )
                }

                override fun onCancel() {
                    callback.onResult(SocialLoginResult.Cancelled(SocialProvider.FACEBOOK))
                }

                override fun onError(error: FacebookException) {
                    callback.onResult(
                        SocialLoginResult.Error(
                            provider = SocialProvider.FACEBOOK,
                            message = error.message ?: "Facebook login failed",
                            exception = error
                        )
                    )
                }
            }
        )
    }

    private fun setupGoogleLogin(): GoogleSignInClient {
        val gso = GoogleSignInOptions.Builder(GoogleSignInOptions.DEFAULT_SIGN_IN)
            .requestEmail()
            .requestProfile()
            // Request server auth code - your backend exchanges this using the client secret
            .requestServerAuthCode(SocialLoginConfig.googleClientId)
            .build()

        return GoogleSignIn.getClient(activity, gso)
    }

    private fun registerGoogleLauncher() {
        googleSignInLauncher = activity.registerForActivityResult(
            ActivityResultContracts.StartActivityForResult()
        ) { result ->
            val task: Task<GoogleSignInAccount> =
                GoogleSignIn.getSignedInAccountFromIntent(result.data)
            handleGoogleSignInResult(task)
        }
    }

    private fun handleGoogleSignInResult(completedTask: Task<GoogleSignInAccount>) {
        try {
            val account = completedTask.getResult(ApiException::class.java)
            // Send serverAuthCode to your BACKEND to exchange for tokens
            callback.onResult(
                SocialLoginResult.Success(
                    provider = SocialProvider.GOOGLE,
                    authorizationCode = account.serverAuthCode,
                    userId = account.id,
                    email = account.email,
                    displayName = account.displayName
                )
            )
        } catch (e: ApiException) {
            if (e.statusCode == 12501) { // Sign-in cancelled
                callback.onResult(SocialLoginResult.Cancelled(SocialProvider.GOOGLE))
            } else {
                callback.onResult(
                    SocialLoginResult.Error(
                        provider = SocialProvider.GOOGLE,
                        message = "Google sign-in failed: ${e.statusCode}",
                        exception = e
                    )
                )
            }
        }
    }

    fun loginWithFacebook() {
        facebookLoginManager.logInWithReadPermissions(
            activity,
            facebookCallbackManager,
            listOf("email", "public_profile")
        )
    }

    fun loginWithGoogle() {
        val signInIntent = googleSignInClient.signInIntent
        googleSignInLauncher.launch(signInIntent)
    }

    fun logout() {
        // Facebook logout
        facebookLoginManager.logOut()
        // Google logout
        googleSignInClient.signOut()
    }

    fun onActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        facebookCallbackManager.onActivityResult(requestCode, resultCode, data)
    }
}

