// --- LoginActivity.kt ---
import android.os.Bundle
import android.util.Log
import android.widget.Button
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity

class LoginActivity : AppCompatActivity(), SocialLoginCallback {

    private lateinit var socialLoginManager: SocialLoginManager

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_login)

        socialLoginManager = SocialLoginManager(this, this)

        findViewById<Button>(R.id.btn_facebook_login).setOnClickListener {
            socialLoginManager.loginWithFacebook()
        }

        findViewById<Button>(R.id.btn_google_login).setOnClickListener {
            socialLoginManager.loginWithGoogle()
        }
    }

    override fun onResult(result: SocialLoginResult) {
        when (result) {
            is SocialLoginResult.Success -> {
                Log.i("Login", "Success via ${result.provider}: ${result.email}")
                // Send result.authorizationCode to YOUR backend server
                // Your backend exchanges it for tokens using the secret stored securely there
                sendAuthCodeToBackend(result.provider, result.authorizationCode)
            }
            is SocialLoginResult.Error -> {
                Log.e("Login", "Error: ${result.message}", result.exception)
                Toast.makeText(this, "Login failed: ${result.message}", Toast.LENGTH_LONG).show()
            }
            is SocialLoginResult.Cancelled -> {
                Log.i("Login", "Cancelled: ${result.provider}")
            }
        }
    }

    private fun sendAuthCodeToBackend(provider: SocialProvider, authCode: String?) {
        // Use Retrofit/OkHttp to POST the auth code to your backend
        // Your backend (where the secrets live) handles the token exchange
        // Example: POST https://your-api.com/auth/social
        // Body: { "provider": "GOOGLE", "authorization_code": "..." }
    }
}